-- Content expansion: 20 NPCs, 20 monsters, 12 items, 5 skills, quests, and events.





CREATE TABLE world_events (
  id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  event_key VARCHAR(120) NOT NULL UNIQUE,
  name VARCHAR(160) NOT NULL,
  dungeon_id BIGINT UNSIGNED NOT NULL,
  floor_id BIGINT UNSIGNED NOT NULL,
  description TEXT NOT NULL,
  trigger_rules_json JSON NOT NULL,
  outcomes_json JSON NOT NULL,
  repeatable TINYINT(1) NOT NULL DEFAULT 0,
  CONSTRAINT fk_world_events_dungeon FOREIGN KEY (dungeon_id) REFERENCES dungeons(id) ON DELETE CASCADE,
  CONSTRAINT fk_world_events_floor FOREIGN KEY (floor_id) REFERENCES dungeon_floors(id) ON DELETE CASCADE
);

CREATE TABLE cycle_events (
  story_cycle_id BIGINT UNSIGNED NOT NULL,
  world_event_id BIGINT UNSIGNED NOT NULL,
  status ENUM('hidden', 'available', 'triggered', 'completed', 'failed') NOT NULL DEFAULT 'hidden',
  state_json JSON NOT NULL,
  triggered_at TIMESTAMP NULL,
  completed_at TIMESTAMP NULL,
  PRIMARY KEY (story_cycle_id, world_event_id),
  CONSTRAINT fk_cycle_events_cycle FOREIGN KEY (story_cycle_id) REFERENCES story_cycles(id) ON DELETE CASCADE,
  CONSTRAINT fk_cycle_events_world FOREIGN KEY (world_event_id) REFERENCES world_events(id) ON DELETE CASCADE
);


SELECT 'fenroot-remedy', 'Medicine for a Living Forest', 'Gather mercy-grown herbs and treat a wounded creature.', id, 1, 103, '{"actionSignatures":["heal","protect"],"required":3}', '{"xp":80,"gold":25,"item":"Soulglass Tonic"}', '{"failureActions":["burn_herbs"]}' FROM world_npcs WHERE name = 'Mara Fenroot' LIMIT 1;

SELECT 'threadseer-futures', 'Cut the Cruel Future', 'Find and sever futures built on hatchling sacrifice.', id, 2, 202, '{"actionSignatures":["analyze","protect","refuse"],"required":3}', '{"xp":110,"gold":35,"item":"Prism Silk"}', '{"failureActions":["accept_sacrifice"]}' FROM world_npcs WHERE name = 'Ilyss Threadseer' LIMIT 1;

SELECT 'free-note', 'The Note That Chose Itself', 'Help the awakened machines create a command-free song.', id, 6, 603, '{"actionSignatures":["create","free","protect"],"required":3}', '{"xp":240,"gold":90,"item":"War Seed Core"}', '{"failureActions":["enslave_machine"]}' FROM world_npcs WHERE name = 'Unit Lark-0' LIMIT 1;

SELECT 'stormshell-home', 'A Village Carried on a Shell', 'Protect refugees while Suri finds ground for a new home.', id, 8, 803, '{"actionSignatures":["protect","explore","befriend"],"required":3}', '{"xp":340,"gold":140,"item":"Tide Scale"}', '{"failureActions":["abandon_refugees"]}' FROM world_npcs WHERE name = 'Suri Stormshell' LIMIT 1;

SELECT 'remember-redacted', 'The Knight the Book Refused', 'Restore the deeds of Redacted Rose without inventing a false identity.', id, 9, 903, '{"actionSignatures":["remember","restore_name","analyze"],"required":3}', '{"xp":420,"gold":180,"item":"Contradiction Ink"}', '{"failureActions":["accept_false_history"]}' FROM world_npcs WHERE name = 'Redacted Rose' LIMIT 1;
